import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListResourcesRequestSchema,
  ListToolsRequestSchema,
  ReadResourceRequestSchema
} from "@modelcontextprotocol/sdk/types.js";

// Instantiate server
const server = new Server(
  {
    name: "diagnostic-server",
    version: "1.0.0"
  },
  {
    capabilities: {
      resources: {},
      tools: {}
    }
  }
);

// List resources handler
server.setRequestHandler(ListResourcesRequestSchema, async () => {
  return {
    resources: [
      {
        uri: "diagnostic://metrics",
        name: "System Performance Metrics",
        mimeType: "application/json",
        description: "Live system diagnostic statistics"
      }
    ]
  };
});

// Read resource handler
server.setRequestHandler(ReadResourceRequestSchema, async (request) => {
  if (request.params.uri === "diagnostic://metrics") {
    return {
      contents: [
        {
          uri: request.params.uri,
          mimeType: "application/json",
          text: JSON.stringify({
            status: "HEALTHY",
            cpu_usage_pct: 12.5,
            memory_free_gb: 8.4,
            timestamp: new Date().toISOString()
          })
        }
      ]
    };
  }
  throw new Error("Resource not found");
});

// List tools handler
server.setRequestHandler(ListToolsRequestSchema, async () => {
  return {
    tools: [
      {
        name: "echo_diagnostics",
        description: "Echoes back status metrics with custom user label",
        inputSchema: {
          type: "object",
          properties: {
            label: {
              type: "string",
              description: "A custom label for the audit logs"
            }
          },
          required: ["label"]
        }
      }
    ]
  };
});

// Call tool handler
server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name === "echo_diagnostics") {
    const label = request.params.arguments?.label || "default";
    return {
      content: [
        {
          type: "text",
          text: `Diagnostics generated with label: [${label}]. All systems nominal.`
        }
      ]
    };
  }
  throw new Error("Tool not found");
});

// Start the server
async function run() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("Diagnostic MCP Server running on stdio");
}

run().catch((error) => {
  console.error("Fatal error:", error);
  process.exit(1);
});

from mcp.server.fastmcp import FastMCP

# Initialize FastMCP Server
mcp = FastMCP("Calculators")

@mcp.tool()
def add_numbers(a: int, b: int) -> str:
    """Adds two integers and returns the formatted sum."""
    return f"The sum of {a} and {b} is {a + b}"

@mcp.resource("config://app")
def get_config() -> str:
    """Returns application configuration file data."""
    return "app_version=1.0.0\nenvironment=development\ndebug_enabled=true"

if __name__ == "__main__":
    mcp.run()
